import react, { useeffect, usestate } from 'react';

function tablecomponent() {
  const records = [
    { id: 1, name: 'adam', age: 25 },
    { id: 2, name: 'james', age: 30 },
    { id: 3, name: 'nick', age: 28 },
    { id: 4, name: 'john', age: 29 }
  ];

  const [filteredrecords, setfilteredrecords] = usestate(records);
  const [sortcolumn, setsortcolumn] = usestate('none');
  const [sortdirection, setsortdirection] = usestate('asc');
  const [searchterm, setsearchterm] = usestate('');

  useeffect(() => {
    let sorted = [...filteredrecords];

    if (sortcolumn !== 'none') {
      sorted.sort((a, b) => {
        if (a[sortcolumn] < b[sortcolumn]) return sortdirection === 'asc' ? -1 : 1;
        if (a[sortcolumn] > b[sortcolumn]) return sortdirection === 'asc' ? 1 : -1;
        return 0;
      });
    }

    setfilteredrecords(sorted);
  }, [sortcolumn, sortdirection, filteredrecords]);

  useeffect(() => {
    if (searchterm === '') {
      setfilteredrecords(records);
    } else {
      const lowercaseterm = searchterm.toLowerCase();
      const filtered = records.filter(record => 
        record.name.toLowerCase().includes(lowercaseterm)
      );
      setfilteredrecords(filtered);
    }
  }, [searchterm]);

  const handlecolumnclick = (column) => {
    if (sortcolumn === column) {
      setsortdirection(sortdirection === 'asc' ? 'desc' : 'asc');
    } else {
      setsortcolumn(column);
      setsortdirection('asc');
    }
  };

  return (
    <div>
      <input
        type="text"
        placeholder="filter by name"
        value={searchterm}
        onChange={(e) => setsearchterm(e.target.value)}
      />
      <table>
        <thead>
          <tr>
            <th onClick={() => handlecolumnclick('id')}>id</th>
            <th onClick={() => handlecolumnclick('name')}>name</th>
            <th onClick={() => handlecolumnclick('age')}>age</
